INSERT INTO public.photos VALUES (22985, 'George Clooney y Arnold Schwarzenegger 1997', 'Los dos actores estadounidenses, en la inauguraciâ”œâ”‚n de los cines Warner Lusomundo en el centro comercial Grancasa del barrio del Actur de Zaragoza, en 1997. Fuente: www.elperiodicodearagon.com/', 1997, 1997, 1997, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66939200, -0.88964600, '0101000020E6100000098D60E3FA77ECBF1E1A16A3AED54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19666380770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19666380770.webp', 'https://www.flickr.com/photos/zaragozaantigua/19666380770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23024, 'Actur 1992', 'Imagen capturada desde la altura de los bloques de viviendas de la calle de Marâ”œÂ¡a Montessori y vertebrada por la perspectiva del alabeado eje central del barrio del Actur, popularmente denominado "la salchicha", flanqueado por las calles de Marâ”œÂ¡a Zambrano a la derecha, y Gertrudis Gâ”œâ”‚mez de Avellaneda a la izquierda, reservado para servicios y que en el momento de realizar esta fotografâ”œÂ¡a ya contaba con una gran superficie comercial inaugurada en 1990, en el tramo al norte de la calle de Pablo Ruiz Picasso. En 1992 la Diputaciâ”œâ”‚n General de Aragâ”œâ”‚n gobernada por la coaliciâ”œâ”‚n PAR-PP aprobâ”œâ”‚ el proyecto presentado por pequeâ”œâ–’os y medianos comerciantes organizados en la sociedad "Grandes â”œÃ¼reas Comerciales de Aragâ”œâ”‚n, S.A.", para construir un gran centro comercial que se ubicarâ”œÂ¡a al fondo de la imagen, en en tramo de "la salchicha" comprendido entre las calles de Mariana Pineda/Nicolâ”œÃ­s Guillâ”œÂ®n y la referida de Pablo Ruiz Picasso, y que serâ”œÂ¡a inaugurado en marzo de 1997.', 1992, 1992, 1992, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66496100, -0.88497800, '0101000020E61000005EBEF561BD51ECBFC70E2A711DD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50201661306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50201661306.webp', 'https://www.flickr.com/photos/zaragozaantigua/50201661306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23044, 'Calle de Marâ”œÂ¡a Zambrano 1991', 'Imagen capturada desde el bloque de viviendas del nâ”¬â•‘ 49 de la calle de Gertrudis Gâ”œâ”‚mez de Avellaneda y centrada parcialmente en el espacio denominado de forma coloquial "la salchicha", delimitado entre esta calle, la paralela de la Poetisa Marâ”œÂ¡a Zambrano, y la perpendicular de Pablo Ruiz Picasso (a la izquierda, fuera de plano), y la avenida del Valle de Broto, al fondo. A esta altura se destacan, en una zona donde seguâ”œÂ¡an creciendo bloques, los inmuebles del nâ”¬â•‘ 16 de la Poetisa Marâ”œÂ¡a Zambrano, el nâ”¬â•‘ 4 de la calle del Poeta Pablo Neruda, y el nâ”¬â•‘ 2 de la calle del Poeta Leâ”œâ”‚n Felipe, ademâ”œÃ­s de la Urbanizaciâ”œâ”‚n Kasâ”œÃ­n. En 1992 la Diputaciâ”œâ”‚n General de Aragâ”œâ”‚n gobernada por la coaliciâ”œâ”‚n PAR-PP aprobâ”œâ”‚ el proyecto presentado por pequeâ”œâ–’os y medianos comerciantes organizados en la sociedad "Grandes â”œÃ¼reas Comerciales de Aragâ”œâ”‚n, S.A.", para construir un gran centro comercial que se habrâ”œÂ¡a de ubicar aquâ”œÂ¡, siendo inaugurado en marzo de 1997. En primer tâ”œÂ®rmino, farolas con carteles publicitarios de los candidatos del PSOE a la alcaldâ”œÂ¡a del Ayuntamiento y a la presidencia de la Diputaciâ”œâ”‚n General en las elecciones de mayo de 1991.', 1991, 1991, 1991, 'Anos 90', 'ACTUR-REY FERNANDO', 41.67000200, -0.88984900, '0101000020E6100000111B2C9CA479ECBF962023A0C2D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50431784766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50431784766.webp', 'https://www.flickr.com/photos/zaragozaantigua/50431784766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24733, 'Polâ”œÂ¡gono de Santiago 1976', 'Aâ”œÂ®rea vista del Polâ”œÂ¡gono de Santiago en 1976, en proceso de delimitaciâ”œâ”‚n urbanâ”œÂ¡stica de solares y viales, previa a su construcciâ”œâ”‚n. En primer plano, el antiguo puente sobre el Ebro ya desmantelado de sus funciones ferroviarias (como la lâ”œÂ¡nea que venâ”œÂ¡a desde la Estaciâ”œâ”‚n del Norte). A la derecha, campos de cultivo y parcelas del Arrabal, y un pedazo de la urbanizaciâ”œâ”‚n Puente de Santiago. Esta enorme pastilla ya tenâ”œÂ¡a dos residentes: el Colegio del Sagrado Corazâ”œâ”‚n, al fondo, trasladado hacâ”œÂ¡a poco desde el Paseo Mola, y su vecino el Colegio El Pilar (Maristas), en pleno frenesâ”œÂ¡ constructivo.', 1976, 1976, 1976, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66500600, -0.89047500, '0101000020E6100000ADFA5C6DC57EECBF67D2A6EA1ED54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866791147.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866791147.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866791147/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24734, 'ACTUR 1976', 'Vista del polâ”œÂ¡gono Actur, al fondo, luego denominado del Rey Fernando. En primer tâ”œÂ®rmino, instalaciones deportivas del Club Nataciâ”œâ”‚n Helios. Al fondo y a la izquierda, la urbanizaciâ”œâ”‚n Kasan, todavâ”œÂ¡a desacompaâ”œâ–’ada de otros edificios. En el centro, el antiguo barrio de La Ortilla-Ranillas vertebrado por el camino de Ranillas, con sus campos de cultivo. Cruza en la parte superior la avenida de los Pirineos, que prosigue luego como carretera de Huesca.', 1976, 1976, 1976, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66270100, -0.88391300, '0101000020E6100000C24B70EA0349ECBF6403E962D3D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14959278361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14959278361.webp', 'https://www.flickr.com/photos/zaragozaantigua/14959278361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24957, 'Parque de Primo de Rivera 1970', 'Imagen capturada desde la altura del cabezo de Buenavista y centrada en el paseo de San Sebastiâ”œÃ­n del parque de Primo de Rivera, donde en primer tâ”œÂ®rmino circula el famoso "tren del parque" por el espacio donde en enero de 1974 se instalâ”œâ”‚ la famosa fuente luminosa proveniente de la plaza de Basilio Paraâ”œÂ¡so. Al fondo, la referente torre-mirador de la Feria de Muestras, la plaza del Emperador Carlos V y el tramo final del paseo de Fernando el Catâ”œâ”‚lico.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63458500, -0.89451600, '0101000020E6100000A5F5B704E09FECBF1EC4CE143AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51680986266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51680986266.webp', 'https://www.flickr.com/photos/zaragozaantigua/51680986266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24779, 'Ortilla-Ranillas 1977', 'Desde las alturas del novâ”œÂ¡simo edificio Kasâ”œÃ­n, excepcional vista panorâ”œÃ­mica de los antiguos, y desaparecidos, barrios de la Ortilla, y de Ranillas, en la margen izquierda del Ebro. El de la Ortilla, a la izquierda, y centro, en el entorno de la carretera de Huesca, y parte del trazado del bucle ferroviario que provenâ”œÂ¡a de la estaciâ”œâ”‚n del Norte. Tras su desmantelamiento en 1976, junto con el paso a nivel que cruzaba la avenida de los Pirineos, este antiguo camino de hierro aparece en la imagen convertido en un ancho (y temporal) camino viario. Junto a â”œÂ®l, las calles Brigadier Gasca, Almutazafe, Antillâ”œâ”‚n, Gâ”œâ”‚mez Butrâ”œâ”‚n. Otra zona del barrio, mâ”œÃ­s central, frente a Helios, junto a la chimenea fabril de "Manufacturas de lanas de Morâ”œâ”‚n y Anâ”œâ”‚s", con las calles Escultor Lasuâ”œÂ®n, Valerio Ripoll, Ortilla, Buenos Aires. El barrio de Ranillas, hacia la derecha, era mâ”œÃ­s vecino del puente del ferrocarril. Entre ambos, se articulaba un difuso entorno periurbano de parcelas, campos de cultivos, riegos, y calles de tierra. Al fondo, tras el Ebro, Zaragoza, tan cerca, y tan lejos. Fuente visual: Josâ”œÂ® Manuel Larroy Calvo, en www.facebook.com/photo.php?fbid=10204683358395723&set...', 1977, 1977, 1977, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66352000, -0.88366800, '0101000020E6100000FFB1101D0247ECBFF71E2E39EED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26568717311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26568717311.webp', 'https://www.flickr.com/photos/zaragozaantigua/26568717311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24812, 'Cocheras Parque Goya 2011', 'Foto: Asier Alcorta. Vista del inicio de la construcciâ”œâ”‚n de las cocheras del tranvâ”œÂ¡a en Parque Goya, en mayo de 2011. En 2013 se pondrâ”œÃ­ en servicio la segunda fase de la lâ”œÂ¡nea 1, habilitâ”œÃ­ndose este espacio como aparcamiento y taller de los convoyes, ademâ”œÃ­s del preexistente en Valdespartera. Tras la Ronda de Boltaâ”œâ–’a y, mâ”œÃ­s allâ”œÃ­, la avenida de la Majas de Goya, se ven edificios del Campus Râ”œÂ¡o Ebro y jalones lejanos como la Estaciâ”œâ”‚n Delicias, el puente del Tercer Milenio y la Torre del Agua. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.68897900, -0.88435600, '0101000020E61000001DAF40F4A44CECBFBE50C07630D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36969643034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36969643034.webp', 'https://www.flickr.com/photos/zaragozaantigua/36969643034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24993, 'Campo de Ranillas c.1995', 'Imagen del "campo de fâ”œâ•‘tbol" de Ranillas habilitado sin grandes inversiones en la esquinera pastilla entre la avenida de Ranillas y la calle del Valle de Broto. Un par de porterâ”œÂ¡as sin red, una pelota, y a jugar. En primer tâ”œÂ®rmino, usuarios de este campo posan junto a su entrenador. Al fondo, bloques inmediatos a la calle del Ebro Viejo, tras la de Valle de Broto. Al fondo y a la derecha, la moderna iglesia parroquial de San Andrâ”œÂ®s Apâ”œâ”‚stol y bloques recayentes a la plaza de la Ortilla. En este espacio se reubicarâ”œÂ¡a, aâ”œâ–’os despuâ”œÂ®s, el Pabellâ”œâ”‚n de Aragâ”œâ”‚n de la Expo 1992, adquirido en 1998 al precio de una peseta por la Confederaciâ”œâ”‚n Regional de Empresarios de Aragâ”œâ”‚n, y desde 2003 su sede social. Poco despuâ”œÂ®s entrarâ”œÂ¡a en funcionamiento el campo municipal de fâ”œâ•‘tbol "Nuevo Ranillas" en unas mâ”œÃ­s norteâ”œâ–’as, occidentales y adecuadas instalaciones junto a la avenida de Ranillas.', 1995, 1995, 1995, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66260500, -0.88725300, '0101000020E610000075E448676064ECBF42959A3DD0D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50431546053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50431546053.webp', 'https://www.flickr.com/photos/zaragozaantigua/50431546053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
