INSERT INTO public.photos VALUES (23163, 'Apartotel Acqua 2007', 'Foto: â”œÃ¼lvaro Calvo. Obras de construcciâ”œâ”‚n del apartotel Acqua, en diciembre de 2007, cuando ya se sabâ”œÂ¡a que no estarâ”œÂ¡a listo para la inauguraciâ”œâ”‚n de la Expo 2008, que le daba supuesta razâ”œâ”‚n de ser. Era uno de los dos establecimientos hoteleros previstos en el meandro de Ranillas, con el faraâ”œâ”‚nico Hiberus. Nunca fue terminado. En 2011, se vendiâ”œâ”‚ al Banco Espirito Santo, que quebrâ”œâ”‚ en 2014. Su estructura degradada permanece varada en el parque del Agua Luis Buâ”œâ–’uel. En 2017 se acondiciona como residencia de ancianos. Fuente: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67241900, -0.90008700, '0101000020E610000087C0914083CDECBFC11A67D311D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32614536515.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32614536515.webp', 'https://www.flickr.com/photos/zaragozaantigua/32614536515/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23416, 'Plataforma Logâ”œÂ¡stica 2006', 'Ortofoto de la Plataforma Logâ”œÂ¡stica de Zaragoza obtenida el 6 de febrero de 2006. Arriba, Canal Imperial de Aragâ”œâ”‚n. A la derecha, Autovâ”œÂ¡a del Nordeste. Fuente: Gobierno de Aragâ”œâ”‚n. Departamento de Presidencia y Relaciones Institucionales. Centro de Documentaciâ”œâ”‚n e Informaciâ”œâ”‚n Territorial de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.64633800, -0.97668400, '0101000020E6100000CBD8D0CDFE40EFBFBE141E34BBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31256847764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31256847764.webp', 'https://www.flickr.com/photos/zaragozaantigua/31256847764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24754, 'Exposiciâ”œâ”‚n Internacional 2008', 'Mapa oficial del recinto de la Exposiciâ”œâ”‚n Internacional "Agua y desarrollo sostenible", celebrada en el Meandro de Ranillas de Zaragoza, del 14 de junio al 14 de septiembre de 2008. Realizado por Expo Agua Zaragoza 2008 S. A. En la ciudad se habâ”œÂ¡an celebrado anteriormente la Exposiciâ”œâ”‚n Aragonesa de 1868 (en el Salâ”œâ”‚n de Pignatelli, actual plaza de Aragâ”œâ”‚n); la Exposiciâ”œâ”‚n Aragonesa de 1885 (en el luego Matadero Municipal); y la Exposiciâ”œâ”‚n Hispano Francesa de 1908 (en la Huerta de Santa Engracia, hoy plaza de Los Sitios). Tras la muestra de 2008, se pretendiâ”œâ”‚ realizar Expo Paisajes (plan B de 2008), de mayo a octubre de 2014 en la Huerta de las Fuentes, pero este proyecto no se llevâ”œâ”‚ a cabo, salvando asâ”œÂ¡ de momento una tercera zona de huertas que se habrâ”œÂ¡a suprimido. Posteriormente se propuso sin â”œÂ®xito como ubicaciâ”œâ”‚n la desembocadura del râ”œÂ¡o Gâ”œÃ­llego. La Expo 2008 supuso la creaciâ”œâ”‚n de edificios que permanecen en la antigua Huerta de Ranillas, como el Pabellâ”œâ”‚n Puente, los de Espaâ”œâ–’a y Aragâ”œâ”‚n, la Torre del Agua, el Acuario fluvial, el Palacio de Congresos y los pabellones de los 108 paâ”œÂ¡ses participantes, estos â”œâ•‘ltimos reconvertidos en oficinas. El grueso de los visitantes, en contra de lo previsto, provino de la propia ciudad.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66991200, -0.90143800, '0101000020E61000008AE42B8194D8ECBF569929ADBFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19291702714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19291702714.webp', 'https://www.flickr.com/photos/zaragozaantigua/19291702714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24790, 'Mijaâ”œÂ¡l Gorbachov 2008', 'Mijaâ”œÂ¡l Gorbachov, mâ”œÃ­ximo dirigente de la Uniâ”œâ”‚n Soviâ”œÂ®tica desde 1985 hasta su disoluciâ”œâ”‚n en 1991, da una conferencia el 9 de septiembre en la Tribuna del Agua de la Expo 2008. Tras â”œÂ®l, una reproducciâ”œâ”‚n de Fluvi, mascota oficial de la muestra, diseâ”œâ–’ada por Sergi Lâ”œâ”‚pez Jordana. Fuente: www.gozazaragoza.com/', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66960600, -0.90194300, '0101000020E61000006765FB90B7DCECBF4A9A3FA6B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31993100644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31993100644.webp', 'https://www.flickr.com/photos/zaragozaantigua/31993100644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24795, 'Noria siria 2008', 'Estructura diseâ”œâ–’ada por Juan Antonio Ros, que soportarâ”œÃ­ la noria situada en la cabecera del parque del Agua Luis Buâ”œâ–’uel. Fue construida por artesanos de Hama, ciudad de Siria, segâ”œâ•‘n una idea de Nicolas Camoisson y Marion Coudert, que la bautizaron como Noria de la Paz. Constaba de 24 brazos y 96 cangilones de madera, que fueron sustituidos por acero corten tres aâ”œâ–’os despuâ”œÂ®s, debido a su deterioro. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67625000, -0.89982900, '0101000020E61000009CC1DF2F66CBECBFC3F5285C8FD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32710571126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32710571126.webp', 'https://www.flickr.com/photos/zaragozaantigua/32710571126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24828, 'Gorbachov en la Expo 2008', 'Imagen de Mijaâ”œÂ¡l Serguâ”œÂ®yevich Gorbachov (1931-2022) capturada durante su visita el dâ”œÂ¡a 9 de septiembre al recinto de la Expo 2008. Personaje central en la historia mundial de finales del siglo XX, fue secretario general del Comitâ”œÂ® Central del Partido Comunista de la Uniâ”œâ”‚n Soviâ”œÂ®tica (1985-1991) y jefe de Estado de la Uniâ”œâ”‚n Soviâ”œÂ®tica (1988-1991). En esta visita se paseâ”œâ”‚ por la Tribuna del Agua y el pabellâ”œâ”‚n de Rusia, antes de subir a Huesca a presentar su libro "Agua para la Paz". Pocos dâ”œÂ¡as despuâ”œÂ®s (19 de septiembre) recibiâ”œâ”‚ la Medalla de la Libertad de Filadelfia 2008, otorgada por el Centro Nacional de la Constituciâ”œâ”‚n de los Estados Unidos de norteamâ”œÂ®rica, presidido por el expresidente George H.W. Bush.', 2008, 2008, 2008, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.66915400, -0.90079700, '0101000020E610000099B7EA3A54D3ECBF69FE98D6A6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52474352209.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52474352209.webp', 'https://www.flickr.com/photos/zaragozaantigua/52474352209/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26060, 'Juslibol 1939', 'Imagen capturada en vuelo y centrada en un bombardero He-111 de â”œâ•‘ltima generaciâ”œâ”‚n (serie E-1, numeral 25-98) que se dirige al aerâ”œâ”‚dromo Sanjurjo de Zaragoza, mientras sobrevuela el norte de Ranillas y el sur del monte de Juslibol, cuyos verticales Cortados delimitan perfectamente la ubâ”œÂ®rrima huerta cercana al râ”œÂ¡o Ebro, que fluye por el antiguo cauce que lamâ”œÂ¡a los Cortados en la zona del Soto del Cabildo. Este aparato, que posiblemente regresa de una misiâ”œâ”‚n en el frente de Cataluâ”œâ–’a, formaba parte del Kampfgruppe 88 de la Legiâ”œâ”‚n Câ”œâ”‚ndor instalado en Zaragoza desde 1937. Casi 100 unidades de este modelo, en tres distintas series, formaron parte del contingente de unos 600 aviones y 16000 soldados que llegaron desde la Alemania nazi para apoyar de forma decisiva el esfuerzo de guerra de los nacionalistas espaâ”œâ–’oles durante la guerra de 1936-39. El de Zaragoza fue uno de sus aerâ”œâ”‚dromos mâ”œÃ­s significados. Fuente visual: foto Francisco Andreu, en www.aviationcorner.net/', 1939, 1939, 1939, 'Anos 30', 'ACTUR-REY FERNANDO', 41.68997900, -0.89803600, '0101000020E6100000552E54FEB5BCECBFA1F65B3B51D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35097343246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35097343246.webp', 'https://www.flickr.com/photos/zaragozaantigua/35097343246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22263, 'Enlace ferroviario 1966', 'El enlace ferroviario de la margen izquierda fue construido a mediados del siglo XIX para unir las lâ”œÂ¡neas de Barcelona y Pamplona, mediante una gran curva trazada por la arboleda de Macanaz, sobre el camino de Ranillas y la huerta de la Ortilla. Con el tiempo, esta zona apenas poblada fue poco a poco siendo urbanizada, dando lugar al barrio de la Ortilla, que esta vista aâ”œÂ®rea aparece delimitado en un espacio mayoritariamente agrâ”œÂ¡cola, con la presencia de alguna instalaciâ”œâ”‚n industrial. Entre el puente de Piedra, al fondo, y el puente del Ferrocarril, en primer tâ”œÂ®rmino, destaca la obra del puente de Santiago, cuyo acceso por la avenida de los Pirineos requiriâ”œâ”‚ instalar un nuevo paso a nivel. En 1973 circulâ”œâ”‚ el â”œâ•‘ltimo tren de pasajeros, y en 1975 se cerrâ”œâ”‚ tambiâ”œÂ®n al trâ”œÃ­fico de mercancâ”œÂ¡as. En 1976 este enlace fue desmantelado, mientras esta perifâ”œÂ®rica zona fue intensamente urbanizada.', 1966, 1966, 1966, 'Anos 60', 'ACTUR-REY FERNANDO', 41.66144100, -0.88240400, '0101000020E6100000B6813B50A73CECBFE59D4319AAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14795533619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14795533619.webp', 'https://www.flickr.com/photos/zaragozaantigua/14795533619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22575, 'Paso a nivel Av. Pirineos 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 10/03/1974. Como forma de enlazar las estaciones del Norte (ferrocarriles a Barcelona), y la de Campo Sepulcro (ferrocarril a Madrid), se construyâ”œâ”‚ un enlace por la margen izquierda, a travâ”œÂ®s de la arboleda de Macanaz, y cruzando el Ebro por el Puente del Ferrocarril (1870). Cuando desde Campo Sepulcro, a travâ”œÂ®s de Miraflores, se pudo hacer directo el trayecto hacia Barcelona, este enlace fue quedando en progresivo desuso. A mediados de los aâ”œâ–’os 70 del pasado siglo circulâ”œâ”‚ el â”œâ•‘ltimo tren de pasajeros, y a principios de los 80 se cerrâ”œâ”‚ tambiâ”œÂ®n al trâ”œÃ­fico de mercancâ”œÂ¡as. Mientras tanto, la Margen Izquierda, antes poco poblada, se estaba llenando de edificios de viviendas, y ya se habâ”œÂ¡a tenido que habilitar un paso a nivel sobre la nueva Avenida de los Pirineos. En la imagen, una de las â”œâ•‘ltimas "vaporosas" por este paso a nivel, camino de la Estaciâ”œâ”‚n del Norte. Al fondo, los montes de Juslibol.', 1974, 1974, 1974, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66194700, -0.88091200, '0101000020E61000002DEDD45C6E30ECBFB857E6ADBAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15415413991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15415413991.webp', 'https://www.flickr.com/photos/zaragozaantigua/15415413991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22629, 'Calle del Almutazafe 1974', 'Imagen de la calle "Almutazafe" del antiguo barrio de "La Ortilla". En torno al lavadero de lanas conocido como "Manufacturas de lanas de Morâ”œâ”‚n y Anâ”œâ”‚s", de finales de la dâ”œÂ®cada de 1910, fueron apareciendo viviendas articuladas en nuevas calles que poco a poco se definieron en la nueva barriada de la Ortilla, a la derecha de la Arboleda o Soto de Macanaz, con entrada por la calle de Garcâ”œÂ¡a Arista, y hasta la lâ”œÂ¡nea del ferrocarril de los Enlaces. Al otro lado del Camino de Ranillas, en los aâ”œâ–’os 20 se estableciâ”œâ”‚ el Centro Naturista Helios, y a mediados de los aâ”œâ–’os 30 el barrio se afirma con calles como Nicolâ”œÃ­s Lomba, Gimâ”œÂ®nez, Vicente Arnal, y Sebastiâ”œÃ­n Banzo. Tras el 18 de julio de 1936, la redenominaciâ”œâ”‚n impuesta de viales tambiâ”œÂ®n alcanzarâ”œÃ­ a esta barriada: ya en 1941, Sebastiâ”œÃ­n Banzo serâ”œÃ­ "Buenos Aires", y desde 1943 Nicolâ”œÃ­s Lomba serâ”œÃ­ "Valero Ripoll", Gimâ”œÂ®nez, "Los Paisanos", y Vicente Arnal, "Ortilla". El crecimiento urbano propiciâ”œâ”‚ luego la apariciâ”œâ”‚n de nuevos viales como Brigadier Gasca, Escultor Lasuâ”œÂ®n, Gâ”œâ”‚mez de Butrâ”œâ”‚n, y esta de la imagen, "Almutazafe", en referencia al antiguo AlmuÃŸÂ©Ã‘tasâ”œÃ­b, responsable municipal de asegurar que la actividad de los mercados se ceâ”œâ–’â”œÂ¡a a las ordenanzas establecidas en lo referido a pesos, medidas y precios. El crecimiento de la Margen Izquierda, sobre todo a partir de la construcciâ”œâ”‚n del Puente de Santiago y la apertura de la Avenida de los Pirineos, junto con la urbanizaciâ”œâ”‚n de la ACTUR, dejâ”œâ”‚ a este antiguo barrio como algo viejo y residual, comparado con los modernos y grandes bloques de viviendas que anunciaban la epifanâ”œÂ¡a del futuro. A mediados de los aâ”œâ–’os 80 del pasado siglo, con la urbanizaciâ”œâ”‚n de las â”œÃ¼reas 15, 16 y 17 de la ACTUR, se consumâ”œâ”‚ la desapariciâ”œâ”‚n por derribo del barrio, de las viejas construcciones, y de su nomenclâ”œÃ­tor. Lo que ha venido despuâ”œÂ®s no conserva ningâ”œâ•‘n vestigio de este pasado, salvo la circunstancial chimenea del lavadero de lanas. En la imagen, la calle Almutazafe junto al curso de la acequia del Brazal', 1974, 1974, 1974, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66199500, -0.88267200, '0101000020E61000008509A359D93EECBFC98E8D40BCD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20163631575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20163631575.webp', 'https://www.flickr.com/photos/zaragozaantigua/20163631575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22724, 'Vista paso a nivel 1973', 'Desde el Edificio de Kasan, una vista en altura de la margen izquierda. Al fondo, y tras la arboleda de Macanaz, vista de la fachada ribereâ”œâ–’a de la ciudad de la que destacan las torres de la Seo y el Pilar, y entre las que sobresale casualmente la torre de viviendas Hâ”œÃ­bitat Don 2000, levantada junto al râ”œÂ¡o Huerva en 1973. La avenida de los Pirineos, en el centro, es cruzada mediante un paso a anivel por la lâ”œÂ¡nea ferroviaria procedente de la estaciâ”œâ”‚n del Arrabal, y con continuidad luego sobre el puente del Ferrocarril hasta la estaciâ”œâ”‚n de Caminreal. A la derecha, el puente de Santiago, proyectado como cruce sobre el Ebro para dar salida a la Vâ”œÂ¡a Imperial hacia el norte. Se ofrece tambiâ”œÂ®n un aspecto parcial del barrio de La Ortilla, en primer tâ”œÂ®rmino. El cierre, poco despuâ”œÂ®s, del citado paso a nivel, acelerarâ”œÃ­ la radical transformaciâ”œâ”‚n de este entorno.', 1973, 1973, 1973, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66141200, -0.88116300, '0101000020E6100000793F6EBF7C32ECBF4A97FE25A9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30471849780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30471849780.webp', 'https://www.flickr.com/photos/zaragozaantigua/30471849780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23045, 'Av. de los Pirineos 1992', 'Imagen de la entrada a Zaragoza a travâ”œÂ®s de la avenida de los Pirineos (antigua carretera de Huesca) que conduce al puente de Santiago, con el tradicional telâ”œâ”‚n de fondo del templo del Pilar. Un poco mâ”œÃ­s adelante se abre la gran rotonda donde confluye el trâ”œÃ­fico desde la calle del Valle de Broto y hacia la derecha da acceso hacia el puente de La Almozara. Esta tâ”œÂ¡pica vista para los usuarios de esta carretera se verâ”œÂ¡a eclipsada cuando a finales de la dâ”œÂ®cada comenzâ”œâ”‚ la construcciâ”œâ”‚n de dos grandes bloques de viviendas en sendos solares de la calle de Palencia, y otros algo mâ”œÃ­s tarde en la de Fernando Gracia Gazulla, en parte recayentes al parque del Tâ”œÂ¡o Jorge.', 1992, 1992, 1992, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66824700, -0.88017200, '0101000020E6100000705B5B785E2AECBF3753211E89D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50432582352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50432582352.webp', 'https://www.flickr.com/photos/zaragozaantigua/50432582352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23233, 'Parque Che Guevara 2021', 'Desde 1988 el comandante Ernesto "Che" Guevara daba nombre a un parque y una calle en el barrio del Actur, en la esquinera ubicaciâ”œâ”‚n entre las calles de Pablo Ruiz Picasso, Pablo Neruda y la avenida de los Pirineos, junto al colegio del Sagrado Corazâ”œâ”‚n. La entrada en el Ayuntamiento y en 2019 del partido polâ”œÂ¡tico de extrema derecha VOX supuso el inicio de una campaâ”œâ–’a para erradicar esta denominaciâ”œâ”‚n que, finalmente y con el respaldo de PP y Ciudadanos, ha sido aprobada a espaldas del movimiento vecinal del barrio. En la imagen, aspecto del antiguo parque del Che Guevara desde su ingreso por la calle de Pablo Neruda a la altura de la parroquia de San Andrâ”œÂ®s Apâ”œâ”‚stol. Hacia el fondo y a la derecha, bloques de viviendas de la calle del Polâ”œÂ¡tico Augusto Bebel.', 2021, 2021, 2021, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.67053900, -0.88243600, '0101000020E61000008E041A6CEA3CECBFA5D8D138D4D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51392689503.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51392689503.webp', 'https://www.flickr.com/photos/zaragozaantigua/51392689503/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24057, 'La Ortilla 1984', 'Foto: Juan Gonzâ”œÃ­lez Misis. Despliegue policial en el barrio de la Ortilla, con motivo de las protestas vecinales ante el plan de instalaciâ”œâ”‚n de 36 viviendas prefabricadas para alojar a poblaciâ”œâ”‚n gitana chabolista. Al fondo, edificio Kasan. Fuente: Heraldo de Aragâ”œâ”‚n.', 1984, 1984, 1984, 'Anos 80', 'ACTUR-REY FERNANDO', 41.66458600, -0.88240800, '0101000020E61000001152B7B3AF3CECBF92B06F2711D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31727004246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31727004246.webp', 'https://www.flickr.com/photos/zaragozaantigua/31727004246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24730, 'Colegio del Sagrado Corazâ”œâ”‚n 1976', '"El 21 de Noviembre de 1800, Magdalena Sofâ”œÂ¡a Barat, funda en Francia la Congregaciâ”œâ”‚n de Religiosas del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s. En Octubre de 1875 abre sus puertas en Zaragoza el Colegio del Sagrado Corazâ”œâ”‚n, que cien aâ”œâ–’os despuâ”œÂ®s, en 1976 se traslada a su actual emplazamiento." Fuente: Fundaciâ”œâ”‚n Sofâ”œÂ¡a Barat. En la foto, el edificio reciâ”œÂ®n construido, con la actual calle Pablo Neruda en primer tâ”œÂ®rmino y la avenida de los Pirineos tras el colegio, atravesada por el puente de la calle Pablo Ruiz Picasso.', 1976, 1976, 1976, 'Anos 70', 'ACTUR-REY FERNANDO', 41.67147700, -0.88287500, '0101000020E61000008D976E128340ECBF138255F5F2D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14758643307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14758643307.webp', 'https://www.flickr.com/photos/zaragozaantigua/14758643307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24753, 'Barrio de Ranillas 1977', 'Con el tâ”œÂ¡tulo de Niâ”œâ–’o y perro, esta fotografâ”œÂ¡a expresionista muestra una de las infraviviendas del barrio de la Ortilla, en la margen izquierda del râ”œÂ¡o Ebro. Como contraste, sobresalen al fondo las torres de la Seo y del Pilar. Este entorno, tan lejos y tan cerca del centro urbano, aunaba asentamientos como el que centra la imagen, con edificaciones de tipologâ”œÂ¡a rural, y estaba â”œÂ¡ntimamente relacionado con el paso del tendido ferroviario en amplia curva, procedente de la estaciâ”œâ”‚n del Arrabal. La urbanizaciâ”œâ”‚n de la zona acabâ”œâ”‚ con todos estos hitos, desplazâ”œÃ­ndolos a otras latitudes mâ”œÃ­s perifâ”œÂ®ricas, donde el chabolismo continâ”œâ•‘a siendo una realidad social. Perduran como â”œâ•‘nicos recuerdos de este entorno la chimenea de la Lanera Aragonesa y la denominaciâ”œâ”‚n de la actual plaza de la Ortilla, en el extremo occidental del barrio del Arrabal, lindando ya con el Actur.', 1977, 1977, 1977, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66350900, -0.88120300, '0101000020E6100000066344A2D032ECBF03CDE7DCEDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19071830190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19071830190.webp', 'https://www.flickr.com/photos/zaragozaantigua/19071830190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24763, 'La Ortilla 1976', 'Foto Peâ”œâ–’a Ramos, 1976. Vista desde el edificio Kasâ”œÃ­n del barrio de La Ortilla de Zaragoza nevado, en la margen izquierda del Ebro, hoy desaparecido. Fuente: www.facebook.com/photo.php?fbid=789703231085642&set=g...', 1976, 1976, 1976, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66228100, -0.88195500, '0101000020E6100000D46531B1F938ECBF8FE1B19FC5D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20382873708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20382873708.webp', 'https://www.flickr.com/photos/zaragozaantigua/20382873708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24777, 'Padre de Huâ”œÂ®rfanos 1977', 'Inâ”œÂ®dita imagen de la desaparecida calle "Padre de Huâ”œÂ®rfanos", vial del antiguo barrio de la Ortilla, entre las calles "Marâ”œÂ¡a de Luna", inmediata, y la de "Antillâ”œâ”‚n" (al fondo). La captura se habrâ”œÂ¡a realizado desde cerca de la avenida de los Pirineos. El trazado ferroviario que provenâ”œÂ¡a de la estaciâ”œâ”‚n del Norte, quedarâ”œÂ¡a a la izquierda, y la moderna mole de Kasâ”œÃ­n, a la derecha. Este espacio urbano perdido sâ”œâ”‚lo perdura en imâ”œÃ­genes como esta, y en la memoria de quienes lo conocieron. Fuente visual: amable aportaciâ”œâ”‚n personal de Pablo Valdâ”œÂ®s.', 1977, 1977, 1977, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66338400, -0.88175800, '0101000020E610000054909F8D5C37ECBF475854C4E9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26364883130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26364883130.webp', 'https://www.flickr.com/photos/zaragozaantigua/26364883130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24818, 'Avenida de Ranillas 1992', 'Imagen centrada en el pabellâ”œâ”‚n municipal de festejos "La Chimenea", que tomâ”œâ”‚ su nombre de la chimenea de la instalaciâ”œâ”‚n industrial de â”œÃ¼ngel Anos y Antonio Morâ”œâ”‚n dedicada al lavado y secado de lana, ampliada luego al curtido de pieles, aquâ”œÂ¡ ubicada en 1917, entre el antiguo camino de Ranillas y la arboleda de Macanaz. Tras el derribo de la fâ”œÃ­brica y urbanizaciâ”œâ”‚n de la zona, se preservâ”œâ”‚ la chimenea en un espacioso solar que en 1991 fue habilitado para dar continuidad a los eventos festivos que hasta entonces se realizaban en el Pabellâ”œâ”‚n Francâ”œÂ®s de la antigua Feria de Muestras. Aquâ”œÂ¡ perdurâ”œâ”‚ hasta que en 1994 fue inaugurado el recinto Multiusos junto al nuevo Auditorio Municipal, de forma que el Ayuntamiento desestimâ”œâ”‚ la continuidad de este itinerante pabellâ”œâ”‚n que acogiâ”œâ”‚ festejos y conciertos. Al fondo de la imagen, inmuebles que jalonan la calle del Arquitecto de La Figuera.', 1992, 1992, 1992, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66095300, -0.88255400, '0101000020E61000000987DEE2E13DECBFB7989F1B9AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50199527818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50199527818.webp', 'https://www.flickr.com/photos/zaragozaantigua/50199527818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24823, 'La Chimenea 1992', 'Imagen capturada en el recinto que albergaba el pabellâ”œâ”‚n municipal de festejos "La Chimenea", montado al calor de la chimenea de las antiguas instalaciones de â”œÃ¼ngel Anos y Antonio Morâ”œâ”‚n dedicadas al lavado y secado de lana y curtido de pieles. Desde 1991 fue el espacio festivo que sustituyâ”œâ”‚ al Pabellâ”œâ”‚n Francâ”œÂ®s de la antigua Feria de Muestras, y estuvo en activo hasta que en 1994 fue inaugurado el recinto Multiusos junto al nuevo Auditorio Municipal. Centra la escena el pabellâ”œâ”‚n y la referida chimenea, ademâ”œÃ­s de las tradicionales casetas que albergan las barras de bebidas espirituosas. Al fondo y a la derecha, el templo del Pilar.', 1992, 1992, 1992, 'Anos 90', 'ACTUR-REY FERNANDO', 41.66088900, -0.88261800, '0101000020E6100000B98C9B1A683EECBFA0A4C00298D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50379633621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50379633621.webp', 'https://www.flickr.com/photos/zaragozaantigua/50379633621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25974, 'Avenida de los Pirineos 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 27/07/1975. "Ciclismo. VII clâ”œÃ­sica Zaragoza-Sabiâ”œâ–’â”œÃ­nigo." En la imagen, la prueba en lâ”œÂ¡nea de salida, en la Avenida de los Pirineos/N-123. Al fondo, panorâ”œÃ­mica de la ciudad, de izquierda a derecha, el Pilar, la arboleda de Macanaz, la barrera levantada del paso a nivel del ferrocarril, San Juan de los Panetes, La Zuda, la iglesia de los Escolapios...', 1975, 1975, 1975, 'Anos 70', 'ACTUR-REY FERNANDO', 41.66259700, -0.88091200, '0101000020E61000002DEDD45C6E30ECBFBFB67EFACFD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15115541239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15115541239.webp', 'https://www.flickr.com/photos/zaragozaantigua/15115541239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20979, 'Râ”œÂ¡o Gâ”œÃ­llego 1820', '"Plano topogrâ”œÃ­fico que manifiesta el curso y madre del Râ”œÂ¡o Gâ”œÃ­llego desde el Soto de Cogullada hasta el Puente de Madera inclusive propio de S. M., las obras y plantaciones hechas por la Administraciâ”œâ”‚n para evitar mayores extravâ”œÂ¡os del Râ”œÂ¡o, las tierras en cultivo a las orillas del mismo y algunos de sus dueâ”œâ–’os, las ramblas con matorral y arbustos y sin ellos, y los cauces por donde ha corrido el Râ”œÂ¡o y corre en sus crecientes. Zaragoza, 3 de mayo de 1806. Adiciones puestas a este Plan tomadas sobre el terreno en febrero de 1820 por el delineador de los Canales, Juan Mendoza." Fuente: DARA/AHPZ.', 1820, 1820, 1820, 'Siglo XIX', 'ACTUR-REY FERNANDO', 41.68329200, -0.84444900, '0101000020E6100000187AC4E8B905EBBF29CFBC1C76D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20462095576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20462095576.webp', 'https://www.flickr.com/photos/zaragozaantigua/20462095576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21932, 'Monasterio de Cogullada 1943', 'Foto: Câ”œÂ®sar Gracia Jarque El Monasterio de Nuestra Seâ”œâ–’ora de Cogullada se encuentra en el camino (hoy carretera) de Cogullada 127 del barrio del mismo nombre de Zaragoza. Convento capuchino de 1657, expulsados sus ocupantes en 1835 y rehabilitado por la Caja de Ahorros en 1943 para Casa de Economâ”œÂ¡a Rural para la formaciâ”œâ”‚n de Labradores Diplomados. Sus sucesivos cambios de nombre: Escuela de Capacitaciâ”œâ”‚n Agraria y Centro de Formaciâ”œâ”‚n para la Empresa, dan una pista sobre la evoluciâ”œâ”‚n econâ”œâ”‚mica de los â”œâ•‘ltimos 70 aâ”œâ–’os. Fuente: Ibercaja.', 1943, 1943, 1943, 'Anos 40', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15018798555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15018798555.webp', 'https://www.flickr.com/photos/zaragozaantigua/15018798555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21996, 'San Gregorio c.1944', 'Inâ”œÂ®dita imagen del ascendente y arbolado ingreso al Campo de Tiro y Maniobras de Alfonso XIII desde la carretera de Huesca. Este terreno formaba parte de los primeros 23 kilâ”œâ”‚metros cuadrados que el Ramo de Guerra adquiriâ”œâ”‚ en este entorno, en 1910-11, por 250.000 pesetas. Destacan las representaciones de "Los Leones" que sobre pedestal flanquean la entrada al Cuartel del General Luque, que por ello tambiâ”œÂ®n era denominado cuartel de Los Leones. En sus inmediaciones fue construida una subestaciâ”œâ”‚n de transformaciâ”œâ”‚n elâ”œÂ®ctrica que recibiâ”œâ”‚ la denominaciâ”œâ”‚n de "Los Leones", y en los aâ”œâ–’os 60 fueron construidos unos depâ”œâ”‚sitos de agua que recibieron la denominaciâ”œâ”‚n de "Depâ”œâ”‚sitos de Los Leones". Este cuartel fue abandonado en 1990 y los leones, desaparecidos. En 2003 el alcalde Josâ”œÂ® Atarâ”œÂ®s, durante la colocaciâ”œâ”‚n de la primera piedra de la urbanizaciâ”œâ”‚n de Valdespartera, anunciâ”œâ”‚ un principio de acuerdo con el Ministerio de Defensa para la construcciâ”œâ”‚n de mâ”œÃ­s de 3200 nuevas viviendas en los suelos de este cuartel ya desaparecido, de las cuales la mitad serâ”œÂ¡a propiedad municipal. A fecha de hoy, todavâ”œÂ¡a no se ha firmado el convenio urbanâ”œÂ¡stico para desarrollar estos suelos, propiedad de la Administraciâ”œâ”‚n General del Estado y adscritos al Ministerio de Defensa.', 1944, 1944, 1944, 'Anos 40', 'ACTUR-REY FERNANDO', 41.69178900, -0.87104200, '0101000020E61000006728EE7893DFEBBFC45DBD8A8CD84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32565134687.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32565134687.webp', 'https://www.flickr.com/photos/zaragozaantigua/32565134687/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22299, 'Dr. Barnard 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo 1968. Con motivo del Aniversario XXV de la IFC (Instituciâ”œâ”‚n "Fernando el Catâ”œâ”‚lico"), se organizâ”œâ”‚ el I Congreso de Medicina Aragonesa (25-28 de mayo). Con ese motivo, se invitâ”œâ”‚ al doctor Christian Barnard para dar una conferencia titulada "Trasplante de corazâ”œâ”‚n", en el auditorio de la Casa de Economâ”œÂ¡a Rural de Cogullada. La Caja pagaba los gastos, por eso se hizo allâ”œÂ¡. Barnard era un mâ”œÂ®dico cirujano sudafricano que pasâ”œâ”‚ a la historia por realizar el primer trasplante de corazâ”œâ”‚n humano del que se tiene constancia.', 1968, 1968, 1968, 'Anos 60', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15546858207.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15546858207.webp', 'https://www.flickr.com/photos/zaragozaantigua/15546858207/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23124, 'Parque Goya 2006', 'Foto: Miriam Martâ”œÂ¡nez. En el aâ”œâ–’o 2000 comenzâ”œâ”‚ a poblarse el nuevo barrio zaragozano Parque Goya, constituido por viviendas de protecciâ”œâ”‚n oficial promovidas por el Gobierno de Aragâ”œâ”‚n. Estâ”œÃ­ dividido en dos por la autovâ”œÂ¡a de Huesca. Parque Goya 1 al este, y Parque Goya 2 al oeste. Esta segunda fase fue habitada a partir de 2003. En la foto de junio de 2006, vecinos del barrio en la calle El Globo, ante el solar donde se construirâ”œÃ­ la parroquia de Santa Marâ”œÂ¡a Reina de los Mâ”œÃ­rtires, inaugurada en 2013. Al fondo, tras la autovâ”œÂ¡a, bloques de los impares de la avenida Majas de Goya, en Parque Goya 2. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.68420700, -0.87321100, '0101000020E6100000143DF03158F1EBBFDE58501894D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31170801583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31170801583.webp', 'https://www.flickr.com/photos/zaragozaantigua/31170801583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23227, 'Camino de los Molinos 2018', 'Vista de mayo de 2018 de la harinera sita en el camino de los Molinos 160-166, frente a la calle de Bernardo Ramazzini. Se trataba del molino harinero "del Papel" o "del Papelillo", que fuera antiguo molino de papel (posiblemente denominado "de las Cavallerias") y luego una fâ”œÃ­brica de tejidos, hasta que a principios del siglo XX se construyera un molino de harina propiedad de Marraco. Fue adquirido a Julio Balena por Antonio Espona en 1946 y se mantuvo en funcionamiento hasta el cambio de siglo. La construcciâ”œâ”‚n permaneciâ”œâ”‚ abandonada, hasta su derribo tras un incendio del 23 de marzo de 2019.', 2018, 2018, 2018, 'Siglo XXI', 'ACTUR-REY FERNANDO', 41.68351300, -0.86691100, '0101000020E6100000705D3123BCBDEBBF07B29E5A7DD74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54379892346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54379892346.webp', 'https://www.flickr.com/photos/zaragozaantigua/54379892346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24082, 'Cogullada 1943', 'Imagen capturada en el Salâ”œâ”‚n de Actos del antiguo monasterio benedictino de Nuestra Seâ”œâ–’ora de Cogullada durante la inauguraciâ”œâ”‚n de la moderna Casa de Economâ”œÂ¡a Rural allâ”œÂ¡ ubicada, impulsada por la Caja de Ahorros y Monte de Piedad de Zaragoza. En pie, el ministro de Educaciâ”œâ”‚n Nacional, el turolense Josâ”œÂ® Ibâ”œÃ­â”œâ–’ez Martâ”œÂ¡n, discursea sobre el apoyo del râ”œÂ®gimen de Franco a esta iniciativa. A la izquierda, Josâ”œÂ® Sinuâ”œÂ®s Urbiola, presidente de la entidad de ahorro local, junto a otros jerarcas locales. Al fondo, diversos sâ”œÂ¡mbolos e iconos institucionales de la Espaâ”œâ–’a salida del 18 de julio de 1936. Fuente visual: www.todocoleccion.net/', 1943, 1943, 1943, 'Anos 40', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39517001694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39517001694.webp', 'https://www.flickr.com/photos/zaragozaantigua/39517001694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24367, 'Monasterio de Cogullada aâ”œâ–’os 20', 'AHPZ. Gabriel Faci. Aâ”œâ–’os 20. "Fachada de una iglesia con pâ”œâ”‚rtico de cinco arcos y torres (sic) de estilo mudâ”œÂ®jar." El monasterio capuchino de Ntra. Sra. de Cogullada fue fundado en 1657, junto a la ermita de la Virgen de Cogullada. Tras la exclaustraciâ”œâ”‚n de 1835, se acabaron los capuchinos. En 1896 unos franceses benedictinos se instalaron aquâ”œÂ¡, e insuflaron al edificio un aire mâ”œÃ­s francâ”œÂ®s. En 1934, consumido ya todo ese aire francâ”œÂ®s, vendieron la propiedad, que fue adquirida en 1940 por una entidad de ahorro local. En la imagen, despejada fachada del Monasterio junto al camino de Cogullada, en su etapa de ocupaciâ”œâ”‚n francesa, sin verja, vallas, carteles de no pasar.', 1920, 1920, 1929, 'Anos 20', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15439252801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15439252801.webp', 'https://www.flickr.com/photos/zaragozaantigua/15439252801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24368, 'Monasterio de Cogullada 1913', '"Zaragoza. Nuestra Seâ”œâ–’ora de Cogullada (Monasterio de Benedictinos)". Vista general y entrada al antiguo Convento de Capuchinos, restaurado en 1896 y desde entonces, de Benedictinos franceses. A la izquierda: porterâ”œÂ¡a, locutorio y hospederâ”œÂ¡a. Arriba: celdas. En el centro: Biblioteca e Iglesia. A la derecha escuelas y casas de los colonos. Imagen incluida en una serie postal sobre este Monasterio. Fuente visual: www.delcampe.es/', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68948800, -0.84665000, '0101000020E61000009D11A5BDC117EBBF027E8D2441D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15459058976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15459058976.webp', 'https://www.flickr.com/photos/zaragozaantigua/15459058976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24379, 'Monasterio de Cogullada 1913', '"Zaragoza. Nâ”¬Â¬ Sâ”¬Â¬ de Cogullada (Monasterio de Benedictinos). Vista desde Noroeste. Abajo: Sacristâ”œÂ¡a, camarâ”œÂ¡n, sala capitular, sala de los Hermanos y cocina. Arriiba: Escritorio, celdas y Biblioteca." El monasterio capuchino de Nuestra. Seâ”œâ–’ora de Cogullada fue fundado en 1657, junto a la ermita de la Virgen de Cogullada, cuya imagen fue descubierta por una humilde mujer guiada por el canto de una "cogujada", ave que en la zona se denominaba "cogulada", segâ”œâ•‘n una tradiciâ”œâ”‚n confesional de la zona. Fue levantado en formas y aires barrocos segâ”œâ•‘n diseâ”œâ–’o de Felipe Busiâ”œâ–’ac y Borbâ”œâ”‚n entre 1658 y 1663. Tras la exclaustraciâ”œâ”‚n de 1835, los capuchinos se marcharon, y en 1896 llegaron unos franceses benedictinos que se instalaron, e insuflaron al edificio un aire mâ”œÃ­s francâ”œÂ®s. Asâ”œÂ¡, la imagen de esta postal captura las traseras del monasterio antes de las grandes reformas francesas, que entre 1913 y 1916 incluyeron una nueva y caracterâ”œÂ¡stica torre neomudâ”œÂ®jar que aquâ”œÂ¡ no aparece, a la izquierda de la espadaâ”œâ–’a, junto a la puerta principal de acceso. En la fotografâ”œÂ¡a, ademâ”œÃ­s, parte de las grandes extensiones de herbâ”œÃ­ceas que la vega del Gâ”œÃ­llego permitâ”œÂ¡a, antes de dejar de ser el râ”œÂ¡o que fue. Imagen incluida en una serie postal sobre este Monasterio. Esta imagen ha sido luego amablemente utilizada en el libro "El monasterio de Cogullada", firmado por Mâ”¬Â¬ Isabel Olivâ”œÃ­n Jarque (2017. Fuente visual de la imagen: www.delcampe.net/, comentada para el Gran Archivo Zaragoza Antigua.', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68948800, -0.84665000, '0101000020E61000009D11A5BDC117EBBF027E8D2441D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20621450646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20621450646.webp', 'https://www.flickr.com/photos/zaragozaantigua/20621450646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24996, 'P.â”¬â•‘ de los Ruiseâ”œâ–’ores 1931', 'Inâ”œÂ®dita imagen capturada en el interior del nâ”œâ•‘mero 23 del paseo de los Ruiseâ”œâ–’ores, junto a la verja que daba a ese paseo y que se abrâ”œÂ¡a en ocasiones contadas para dar acceso al Jardâ”œÂ¡n Botâ”œÃ­nico de la ciudad, allâ”œÂ¡ ubicado desde 1923. Al fondo, escalerillas que comunicaban con el edificio central de la Residencia de Estudiantes o Colegio Mayor de Cerbuna de la Universidad de Zaragoza.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63570000, -0.88984900, '0101000020E6100000111B2C9CA479ECBF9A081B9E5ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53174662519.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53174662519.webp', 'https://www.flickr.com/photos/zaragozaantigua/53174662519/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24383, 'Zaragoza desde Cogullada 1913', 'El monasterio capuchino de Nuestra Seâ”œâ–’ora de Cogullada fue fundado en 1657, junto a la ermita de la Virgen de Cogullada, cuyo icono representativo fue descubierto por unos pâ”œÃ­jaros, segâ”œâ•‘n mitos y leyendas del folclore local. El conjunto monacal fue construido en formas y pensamiento barroco, segâ”œâ•‘n diseâ”œâ–’o de Felipe Busiâ”œâ–’ac. Tras la exclaustraciâ”œâ”‚n de 1835, los capuchinos se marcharon, y en 1896 llegaron unos benedictinos que se instalaron e insuflaron al edificio un aire mâ”œÃ­s francâ”œÂ®s. Entre 1913 y 1916 aâ”œâ–’adieron al conjunto una nueva torre neomudâ”œÂ®jar que se convirtiâ”œâ”‚ en su referente visual mâ”œÃ­s representativo. Antes de eso, un poderoso torreâ”œâ”‚n cuadrangular o mirador de la hospederâ”œÂ¡a, venâ”œÂ¡a siendo la atalaya mâ”œÃ­s alta del monasterio. Desde allâ”œÂ¡, precisamente, se capturâ”œâ”‚ la imagen de esta entrada, con visual del antiguo camino de Cogullada, y de la feraz vega del Gâ”œÃ­llego. A lo lejos, a unos 4,5 kilâ”œâ”‚metros en lâ”œÂ¡nea recta, las dos torres y la câ”œâ•‘pula central del Pilar nos seâ”œâ–’alan dâ”œâ”‚nde queda Zaragoza. Esta imagen ha sido luego amablemente utilizada en el libro "El monasterio de Cogullada", firmado por Mâ”¬Â¬ Isabel Olivâ”œÃ­n Jarque (2017. Fuente visual: www.delcampe.net/ comentada para el Gran Archivo Zaragoza Antigua.', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22795080787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22795080787.webp', 'https://www.flickr.com/photos/zaragozaantigua/22795080787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24389, 'Monasterio de Cogullada 1913', '"Zaragoza. Nuestra Seâ”œâ–’ora de Cogullada (Monasterio de Benedictinos)". Vista y entrada al antiguo convento de Capuchinos, restaurado en 1896 y desde entonces, de Benedictinos franceses. A la izquierda: porterâ”œÂ¡a, locutorio y hospederâ”œÂ¡a. Arriba: celdas. En el centro: Biblioteca e Iglesia. A la derecha: camino de Cogullada. Imagen incluida en una serie postal sobre este Monasterio. Esta imagen ha sido luego amablemente utilizada en el libro "El monasterio de Cogullada", firmado por Mâ”¬Â¬ Isabel Olivâ”œÃ­n Jarque (2017. Fuente visual de la imagen: www.delcampe.es/, comentada para el Gran Archivo Zaragoza Antigua.', 1913, 1913, 1913, 'Anos 10', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24669705150.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24669705150.webp', 'https://www.flickr.com/photos/zaragozaantigua/24669705150/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24391, 'Monasterio Cogullada 1933', 'Imagen del antiguo monasterio capuchino de Nâ”¬Â¬. Sâ”¬Â¬. de Cogullada, usufructuado desde 1896 por monjes franceses benedictinos, poco antes de abandonarlo y ponerlo en venta. En 1940 serâ”œÃ­ adquirido por una entidad de ahorro local, para usos varios, incluyendo el de residencia oficial de destacadas personalidades y jefes del Estado, como Franco, y Juan Carlos I. La vista se ha capturado desde el plurisecular camino de Cogullada. Fuente visual: Revista "Mundo Grâ”œÃ­fico".', 1933, 1933, 1933, 'Anos 30', 'ACTUR-REY FERNANDO', 41.68916200, -0.84696600, '0101000020E6100000AF5DDA70581AEBBFAFD2DD7536D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24937412506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24937412506.webp', 'https://www.flickr.com/photos/zaragozaantigua/24937412506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
